/// A connected TCP socket, served on the channel `network.connect` hands back as a
/// capability: send bytes (passed zero-copy as a `buffer` - a shared-memory handle,
/// so the payload never crosses the channel), receive incoming bytes as a
/// wait-drained event stream of chunks (the producer closes when the peer closes -
/// end of stream), and close. The socket is the canonical object; each net tool asks
/// NetworkService for the socket it needs and talks this contract.
// interface `socket` over a channel: opcodes, a Service trait + dispatch, and a Client.
pub mod socket {
	use super::*;
	use crate::codec::{Reader, Sink, SliceWriter, Transport, VecWriter};
	use alloc::vec::Vec;

	pub const OP_SEND: u16 = 1;
	pub const OP_RECV: u16 = 2;
	pub const OP_CLOSE: u16 = 3;

	pub trait Service {
		fn send(&mut self, data: crate::codec::Buffer) -> Result<u32, Error>;
		fn recv(&mut self) -> Vec<Chunk>;
		fn close(&mut self) -> Result<(), Error>;
	}

	pub fn dispatch<S: Service>(service: &mut S, request: &[u8], request_handle: &mut u64, out: &mut [u8], reply_handle: &mut u64) -> Option<usize> {
		let mut reader = if *request_handle == 0 { Reader::new(request) } else { Reader::with_handle(request, *request_handle) };
		let r = &mut reader;
		let op = r.u16()?;
		let corr = r.u32()?;
		let mut writer = SliceWriter::new(out);
		match op {
			OP_SEND => {
				let data = {
					let len = r.u64()?;
					let handle = r.take_handle()?;
					crate::codec::Buffer { handle, len }
				};
				if r.has_handle() {
					return None;
				}
				*request_handle = 0;
				let result = service.send(data);
				let encoded: Option<()> = (|| {
					let w = &mut writer;
					w.u32(corr)?;
					match &result {
						Ok(v38) => {
							w.u8(1)?;
							w.u32(*v38)?;
						}
						Err(v39) => {
							w.u8(0)?;
							v39.write(w)?;
						}
					}
					Some(())
				})();
				if encoded.is_none() {
					if writer.has_handle() {
						*reply_handle = writer.handle();
						return None;
					}
					// the reply outgrew the caller's buffer: replace it with a typed
					// error, so the client sees a failure instead of hanging.
					writer.reset();
					let w = &mut writer;
					w.u32(corr)?;
					w.u8(0)?;
					Error::Again.write(w)?;
				}
			}
			OP_CLOSE => {
				if r.has_handle() {
					return None;
				}
				*request_handle = 0;
				let result = service.close();
				let encoded: Option<()> = (|| {
					let w = &mut writer;
					w.u32(corr)?;
					match &result {
						Ok(v40) => {
							w.u8(1)?;
						}
						Err(v41) => {
							w.u8(0)?;
							v41.write(w)?;
						}
					}
					Some(())
				})();
				if encoded.is_none() {
					if writer.has_handle() {
						*reply_handle = writer.handle();
						return None;
					}
					// the reply outgrew the caller's buffer: replace it with a typed
					// error, so the client sees a failure instead of hanging.
					writer.reset();
					let w = &mut writer;
					w.u32(corr)?;
					w.u8(0)?;
					Error::Again.write(w)?;
				}
			}
			_ => return None,
		}
		*reply_handle = writer.handle();
		Some(writer.pos())
	}

	pub fn recv_open<S: Service>(service: &mut S, request: &[u8], request_handle: &mut u64) -> Option<(u32, Vec<Chunk>)> {
		let mut reader = if *request_handle == 0 { Reader::new(request) } else { Reader::with_handle(request, *request_handle) };
		let r = &mut reader;
		let _op = r.u16()?;
		let corr = r.u32()?;
		if r.has_handle() {
			return None;
		}
		*request_handle = 0;
		let items = service.recv();
		Some((corr, items))
	}
	pub fn recv_frame(seq: u32, item: &Chunk, out: &mut [u8], frame_handle: &mut u64) -> Option<usize> {
		let mut writer = SliceWriter::new(out);
		let encoded: Option<()> = (|| {
			let w = &mut writer;
			w.u32(seq)?;
			item.write(w)?;
			Some(())
		})();
		if encoded.is_none() {
			if writer.has_handle() {
				*frame_handle = writer.handle();
			}
			return None;
		}
		*frame_handle = writer.handle();
		Some(writer.pos())
	}
	pub fn recv_read(msg: &[u8], frame_handle: &mut u64) -> Option<Chunk> {
		let mut reader = if *frame_handle == 0 { Reader::new(msg) } else { Reader::with_handle(msg, *frame_handle) };
		let r = &mut reader;
		let _seq = r.u32()?;
		let value = Chunk::read(r)?;
		if reader.has_handle() {
			return None;
		}
		*frame_handle = 0;
		Some(value)
	}

	pub struct Client<T: Transport> {
		transport: T,
		corr: u32,
	}

	impl<T: Transport> Client<T> {
		pub fn new(transport: T) -> Client<T> {
			Client { transport, corr: 0 }
		}
		pub fn into_transport(self) -> T {
			self.transport
		}
		fn next_corr(&mut self) -> u32 {
			let c = self.corr;
			self.corr = self.corr.wrapping_add(1);
			c
		}
		pub fn send(&mut self, data: &crate::codec::Buffer) -> Option<Result<u32, Error>> {
			let corr = self.next_corr();
			let mut writer = VecWriter::new();
			let w = &mut writer;
			w.u16(OP_SEND)?;
			w.u32(corr)?;
			w.set_handle(data.handle)?;
			w.u64(data.len)?;
			let request_handle = writer.handle();
			let request = writer.into_inner();
			let (reply, reply_handle) = self.transport.call(&request, request_handle)?;
			let mut reader = if reply_handle == 0 { Reader::new(&reply) } else { Reader::with_handle(&reply, reply_handle) };
			let decoded = (|| {
				let r = &mut reader;
				if r.u32()? != corr {
					return None;
				}
				Some(if r.u8()? != 0 { Ok(r.u32()?) } else { Err(Error::read(r)?) })
			})();
			if decoded.is_none() || reader.has_handle() {
				if reply_handle != 0 {
					self.transport.discard_handle(reply_handle);
				}
				return None;
			}
			decoded
		}
		pub fn recv(&mut self) -> Option<u64> {
			let corr = self.next_corr();
			let mut writer = VecWriter::new();
			let w = &mut writer;
			w.u16(OP_RECV)?;
			w.u32(corr)?;
			let request_handle = writer.handle();
			let request = writer.into_inner();
			let (reply, reply_handle) = self.transport.call(&request, request_handle)?;
			let mut reader = Reader::new(&reply);
			let r = &mut reader;
			if r.u32()? != corr || reply_handle == 0 {
				if reply_handle != 0 {
					self.transport.discard_handle(reply_handle);
				}
				return None;
			}
			Some(reply_handle)
		}
		pub fn close(&mut self) -> Option<Result<(), Error>> {
			let corr = self.next_corr();
			let mut writer = VecWriter::new();
			let w = &mut writer;
			w.u16(OP_CLOSE)?;
			w.u32(corr)?;
			let request_handle = writer.handle();
			let request = writer.into_inner();
			let (reply, reply_handle) = self.transport.call(&request, request_handle)?;
			let mut reader = if reply_handle == 0 { Reader::new(&reply) } else { Reader::with_handle(&reply, reply_handle) };
			let decoded = (|| {
				let r = &mut reader;
				if r.u32()? != corr {
					return None;
				}
				Some(if r.u8()? != 0 { Ok(()) } else { Err(Error::read(r)?) })
			})();
			if decoded.is_none() || reader.has_handle() {
				if reply_handle != 0 {
					self.transport.discard_handle(reply_handle);
				}
				return None;
			}
			decoded
		}
	}

	#[cfg(feature = "channel-client-impl")]
	#[inline(never)]
	#[unsafe(export_name = "liber_channel_impl_liber_network_socket_send")]
	fn channel_invoke_send(chan: u64, data: &crate::codec::Buffer) -> Option<Result<u32, Error>> {
		let mut client = Client::new(ipc_client::ChannelTransport { chan });
		client.send(data)
	}

	#[cfg(feature = "channel-client-impl")]
	#[inline(never)]
	#[unsafe(export_name = "liber_channel_impl_liber_network_socket_recv")]
	fn channel_invoke_recv(chan: u64) -> Option<u64> {
		let mut client = Client::new(ipc_client::ChannelTransport { chan });
		client.recv()
	}

	#[cfg(feature = "channel-client-impl")]
	#[inline(never)]
	#[unsafe(export_name = "liber_channel_impl_liber_network_socket_close")]
	fn channel_invoke_close(chan: u64) -> Option<Result<(), Error>> {
		let mut client = Client::new(ipc_client::ChannelTransport { chan });
		client.close()
	}
}

/// One chunk of received socket data, the element of the `socket.recv` stream.
#[derive(Clone, Debug, PartialEq)]
pub struct Chunk {
	pub data: Vec<u8>,
}

impl Chunk {
	pub fn encode(&self, out: &mut [u8]) -> Option<usize> {
		let mut w = SliceWriter::new(out);
		self.write(&mut w)?;
		Some(w.pos())
	}
	pub fn encode_vec(&self) -> Option<Vec<u8>> {
		let mut w = VecWriter::new();
		self.write(&mut w)?;
		Some(w.into_inner())
	}
	pub fn decode(bytes: &[u8]) -> Option<Chunk> {
		Chunk::read(&mut Reader::new(bytes))
	}
	pub(crate) fn write<W: Sink>(&self, w: &mut W) -> Option<()> {
		if self.data.len() > u16::MAX as usize {
			return None;
		}
		w.u16(self.data.len() as u16)?;
		for v42 in self.data.iter() {
			w.u8(*v42)?;
		}
		Some(())
	}
	pub(crate) fn read(r: &mut Reader) -> Option<Chunk> {
		let data = {
			let v43 = r.u16()? as usize;
			let mut v44 = Vec::new();
			for _ in 0..v43 {
				v44.push(r.u8()?);
			}
			v44
		};
		Some(Chunk { data })
	}
}

/// A listening socket from `network.listen`, served on the channel it hands back.
/// `accept` waits until an inbound connection completes its handshake, then hands it
/// back as a `socket` capability (the channel a `socket` interface is served on) - the
/// passive-open counterpart to `network.connect`. The server calls `accept` in a loop,
/// each call yielding the next connection.
// interface `listener` over a channel: opcodes, a Service trait + dispatch, and a Client.
pub mod listener {
	use super::*;
	use crate::codec::{Reader, Sink, SliceWriter, Transport, VecWriter};
	use alloc::vec::Vec;

	pub const OP_ACCEPT: u16 = 1;

	pub trait Service {
		fn accept(&mut self) -> Result<u64, Error>;
	}

	pub fn dispatch<S: Service>(service: &mut S, request: &[u8], request_handle: &mut u64, out: &mut [u8], reply_handle: &mut u64) -> Option<usize> {
		let mut reader = if *request_handle == 0 { Reader::new(request) } else { Reader::with_handle(request, *request_handle) };
		let r = &mut reader;
		let op = r.u16()?;
		let corr = r.u32()?;
		let mut writer = SliceWriter::new(out);
		match op {
			OP_ACCEPT => {
				if r.has_handle() {
					return None;
				}
				*request_handle = 0;
				let result = service.accept();
				let encoded: Option<()> = (|| {
					let w = &mut writer;
					w.u32(corr)?;
					match &result {
						Ok(v45) => {
							w.u8(1)?;
							w.set_handle(*v45)?;
							w.u32(0)?;
						}
						Err(v46) => {
							w.u8(0)?;
							v46.write(w)?;
						}
					}
					Some(())
				})();
				if encoded.is_none() {
					if writer.has_handle() {
						*reply_handle = writer.handle();
						return None;
					}
					// the reply outgrew the caller's buffer: replace it with a typed
					// error, so the client sees a failure instead of hanging.
					writer.reset();
					let w = &mut writer;
					w.u32(corr)?;
					w.u8(0)?;
					Error::Again.write(w)?;
				}
			}
			_ => return None,
		}
		*reply_handle = writer.handle();
		Some(writer.pos())
	}

	pub struct Client<T: Transport> {
		transport: T,
		corr: u32,
	}

	impl<T: Transport> Client<T> {
		pub fn new(transport: T) -> Client<T> {
			Client { transport, corr: 0 }
		}
		pub fn into_transport(self) -> T {
			self.transport
		}
		fn next_corr(&mut self) -> u32 {
			let c = self.corr;
			self.corr = self.corr.wrapping_add(1);
			c
		}
		pub fn accept(&mut self) -> Option<Result<u64, Error>> {
			let corr = self.next_corr();
			let mut writer = VecWriter::new();
			let w = &mut writer;
			w.u16(OP_ACCEPT)?;
			w.u32(corr)?;
			let request_handle = writer.handle();
			let request = writer.into_inner();
			let (reply, reply_handle) = self.transport.call(&request, request_handle)?;
			let mut reader = if reply_handle == 0 { Reader::new(&reply) } else { Reader::with_handle(&reply, reply_handle) };
			let decoded = (|| {
				let r = &mut reader;
				if r.u32()? != corr {
					return None;
				}
				Some(if r.u8()? != 0 {
					Ok({
						let _ = r.u32()?;
						r.take_handle()?
					})
				} else {
					Err(Error::read(r)?)
				})
			})();
			if decoded.is_none() || reader.has_handle() {
				if reply_handle != 0 {
					self.transport.discard_handle(reply_handle);
				}
				return None;
			}
			decoded
		}
	}

	#[cfg(feature = "channel-client-impl")]
	#[inline(never)]
	#[unsafe(export_name = "liber_channel_impl_liber_network_listener_accept")]
	fn channel_invoke_accept(chan: u64) -> Option<Result<u64, Error>> {
		let mut client = Client::new(ipc_client::ChannelTransport { chan });
		client.accept()
	}
}

